import { MittwaldAPIV2Client } from '@mittwald/api-client';

const token = process.env.TEST_CLI_TOKEN || process.env.MITTWALD_API_TOKEN;
if (!token) {
  console.error('Error: TEST_CLI_TOKEN or MITTWALD_API_TOKEN environment variable is required');
  process.exit(1);
}

const client = MittwaldAPIV2Client.newWithToken(token);

console.log('=== FETCHING ALL PROJECTS ===\n');

try {
  // First, get all projects
  const projectsResponse = await client.project.listProjects({});

  if (projectsResponse.status === 200 && projectsResponse.data) {
    console.log(`Found ${projectsResponse.data.length} projects:\n`);

    for (const project of projectsResponse.data) {
      console.log(`\n${'='.repeat(80)}`);
      console.log(`PROJECT: ${project.description || 'Unnamed Project'}`);
      console.log(`ID: ${project.id}`);
      console.log(`Created: ${project.createdAt || 'N/A'}`);
      console.log(`Server ID: ${project.serverId || 'N/A'}`);
      console.log(`${'='.repeat(80)}\n`);

      // For each project, list containers
      try {
        console.log(`  Fetching containers for project ${project.id}...`);
        const containersResponse = await client.container.listContainers({
          projectId: project.id
        });

        if (containersResponse.status === 200 && containersResponse.data) {
          if (containersResponse.data.length === 0) {
            console.log(`  No containers found in this project.\n`);
          } else {
            console.log(`  Found ${containersResponse.data.length} containers:\n`);

            containersResponse.data.forEach((container, index) => {
              console.log(`  ${index + 1}. Container ID: ${container.id}`);
              console.log(`     Description: ${container.description || 'N/A'}`);
              console.log(`     Image: ${container.image || 'N/A'}`);
              console.log(`     Status: ${container.status || 'N/A'}`);

              // Show port mappings if available
              if (container.ports && container.ports.length > 0) {
                console.log(`     Ports:`);
                container.ports.forEach(port => {
                  const portInfo = port.port ? `:${port.port}` : '';
                  const protocol = port.protocol ? ` (${port.protocol})` : '';
                  console.log(`       - ${portInfo}${protocol}`);
                });
              }

              // Show volumes if available
              if (container.volumes && container.volumes.length > 0) {
                console.log(`     Volumes:`);
                container.volumes.forEach(vol => {
                  console.log(`       - ${vol.path || 'N/A'} ${vol.name ? `(${vol.name})` : ''}`);
                });
              }

              console.log('');
            });
          }
        } else {
          console.log(`  Could not fetch containers (status: ${containersResponse.status})\n`);
        }
      } catch (containerError) {
        console.log(`  Error fetching containers: ${containerError.message}\n`);
      }
    }

    console.log(`\n${'='.repeat(80)}`);
    console.log(`SUMMARY: ${projectsResponse.data.length} total projects`);
    console.log(`${'='.repeat(80)}\n`);

  } else {
    console.log('No projects found or error occurred');
    console.log('Status:', projectsResponse.status);
  }
} catch (error) {
  console.error('Error listing projects:', error.message);
  if (error.response) {
    console.error('Response status:', error.response.status);
    console.error('Response data:', error.response.data);
  }
}

