import { MittwaldAPIV2Client } from '@mittwald/api-client';

const token = process.env.TEST_CLI_TOKEN || process.env.MITTWALD_API_TOKEN;
if (!token) {
  console.error('Error: TEST_CLI_TOKEN or MITTWALD_API_TOKEN environment variable is required');
  process.exit(1);
}

const client = MittwaldAPIV2Client.newWithToken(token);

console.log('=== MITTWALD PROJECTS AND CONTAINERS OVERVIEW ===\n');

try {
  const projectsResponse = await client.project.listProjects({});

  if (projectsResponse.status === 200 && projectsResponse.data) {
    console.log(`Found ${projectsResponse.data.length} projects\n`);

    for (const project of projectsResponse.data) {
      console.log(`\n${'='.repeat(100)}`);
      console.log(`PROJECT: ${project.description || 'Unnamed Project'}`);
      console.log(`${'='.repeat(100)}`);
      console.log(`  Project ID:    ${project.id}`);
      console.log(`  Server ID:     ${project.serverId || 'N/A'}`);
      console.log(`  Created:       ${project.createdAt ? new Date(project.createdAt).toLocaleString() : 'N/A'}`);
      console.log(`  Cluster ID:    ${project.clusterPk || 'N/A'}`);
      console.log(`${'='.repeat(100)}\n`);

      // Fetch containers/services for this project
      console.log(`  🔍 Fetching containers/services...\n`);

      try {
        const servicesUrl = `https://api.mittwald.de/v2/projects/${project.id}/services`;
        const response = await fetch(servicesUrl, {
          headers: {
            'Authorization': `Bearer ${token}`,
            'Accept': 'application/json'
          }
        });

        if (response.ok) {
          const services = await response.json();

          if (services && services.length > 0) {
            console.log(`  ✓ Found ${services.length} container(s):\n`);

            for (const service of services) {
              console.log(`  ┌─ Container`);
              console.log(`  │  ID:          ${service.id}`);
              console.log(`  │  Description: ${service.description || 'N/A'}`);
              console.log(`  │  Type:        ${service.kind || 'N/A'}`);

              // Try to get more details about the service
              if (service.id) {
                try {
                  const detailUrl = `https://api.mittwald.de/v2/services/${service.id}`;
                  const detailResponse = await fetch(detailUrl, {
                    headers: {
                      'Authorization': `Bearer ${token}`,
                      'Accept': 'application/json'
                    }
                  });

                  if (detailResponse.ok) {
                    const detail = await detailResponse.json();
                    if (detail.image) console.log(`  │  Image:       ${detail.image}`);
                    if (detail.volumes && detail.volumes.length > 0) {
                      console.log(`  │  Volumes:     ${detail.volumes.length} volume(s)`);
                    }
                    if (detail.ports && detail.ports.length > 0) {
                      console.log(`  │  Ports:`);
                      detail.ports.forEach(port => {
                        console.log(`  │    - ${port.port || 'N/A'} (${port.protocol || 'N/A'})`);
                      });
                    }
                    if (detail.environment && Object.keys(detail.environment).length > 0) {
                      console.log(`  │  Environment: ${Object.keys(detail.environment).length} variable(s)`);
                    }
                  }
                } catch (detailError) {
                  // Silently continue if detail fetch fails
                }
              }

              console.log(`  └─`);
              console.log('');
            }
          } else {
            console.log(`  ℹ  No containers found in this project\n`);
          }
        } else {
          const errorText = await response.text();
          console.log(`  ⚠  Could not fetch services (HTTP ${response.status})`);
          if (response.status === 401) {
            console.log(`  ℹ  Authentication error - token may be expired or lack permissions\n`);
          } else if (response.status === 403) {
            console.log(`  ℹ  Access denied - insufficient permissions\n`);
          } else {
            console.log(`  Error: ${errorText.substring(0, 200)}\n`);
          }
        }
      } catch (serviceError) {
        console.log(`  ⚠  Error fetching services: ${serviceError.message}\n`);
      }

      console.log(`  ${'─'.repeat(98)}\n`);
    }

    console.log(`\n${'='.repeat(100)}`);
    console.log(`SUMMARY`);
    console.log(`${'='.repeat(100)}`);
    console.log(`Total Projects: ${projectsResponse.data.length}`);
    console.log(`${'='.repeat(100)}\n`);

  } else {
    console.log('No projects found or error occurred');
    console.log('Status:', projectsResponse.status);
  }
} catch (error) {
  console.error('Error listing projects:', error.message);
  if (error.response) {
    console.error('Response status:', error.response.status);
    console.error('Response data:', error.response.data);
  }
}

